@media (max-width: 1024px) {
  .landing__hero .container { grid-template-columns: 1fr; gap: 3rem; }
  .landing__hero-preview { display: block; }
  .landing__plans-grid { grid-template-columns: 1fr; max-width: 400px; margin-left: auto; margin-right: auto; }
  .landing__ig-compact-inner { grid-template-columns: 1fr; gap: 2.5rem; }
  /* How It Works – 2 cols on tablet */
  .landing__how-steps { grid-template-columns: repeat(2, 1fr); }
  /* What You Get – 3 cols on tablet */
  .landing__wyg-grid { grid-template-columns: repeat(3, 1fr); }
  /* Support – 1 col on tablet */
  .landing__support-grid { grid-template-columns: 1fr; max-width: 480px; margin-left: auto; margin-right: auto; }
}

@media (max-width: 640px) {
  .landing__hero { padding: 4.5rem 0 2.5rem; min-height: unset; }
  .landing__cta-card { padding: 3rem 1.5rem; }
  .landing__cta-full-card { padding: 3.5rem 1.5rem; }
  .landing__hero-actions { flex-direction: column; }
  .landing__hero-actions .btn { width: 100%; justify-content: center; }
  /* Stats: 2×2 grid on mobile */
  .landing__stats-grid { grid-template-columns: repeat(2, 1fr); gap: 1.5rem; }
  .landing__plans-grid { grid-template-columns: 1fr; max-width: 100%; }
  /* How It Works – 1 col on mobile */
  .landing__how-steps { grid-template-columns: 1fr; max-width: 480px; margin-left: auto; margin-right: auto; }
  /* What You Get – 2 cols on mobile, taller flip cards */
  .landing__wyg-grid { grid-template-columns: repeat(2, 1fr); gap: 0.75rem; }
  .wyg-flip { height: auto; perspective: none; }
  .wyg-flip__inner { transform-style: flat; height: auto; position: relative; }
  .wyg-flip__front,
  .wyg-flip__back { position: relative; inset: auto; backface-visibility: visible; -webkit-backface-visibility: visible; border-radius: 12px; }
  .wyg-flip__back { transform: none; display: none; align-items: flex-start; justify-content: flex-start; }
  .wyg-flip.is-flipped .wyg-flip__inner { transform: none; }
  .wyg-flip.is-flipped .wyg-flip__front { display: none; }
  .wyg-flip.is-flipped .wyg-flip__back { display: flex; }
  /* Why ChatGPT – stack on mobile */
  .landing__whychatgpt-table { grid-template-columns: 1fr; }
  .landing__whychatgpt-col--generic { border-right: none; border-bottom: 1px solid var(--border-color); }
  .landing__whychatgpt-row { padding: 0.75rem 1.25rem; font-size: 0.9rem; }
  .landing__ig-compact-preview { flex-direction: column; gap: 1.25rem; }
  .landing__plan-flip { height: auto; perspective: none; }
  .landing__plan-flip__inner { transform-style: flat; height: auto; position: relative; }
  .landing__plan-flip__front,
  .landing__plan-flip__back { position: relative; inset: auto; backface-visibility: visible; -webkit-backface-visibility: visible; }
  .landing__plan-flip__back { display: none; transform: none; }
  .landing__plan-flip.is-flipped .landing__plan-flip__front { display: none; }
  .landing__plan-flip.is-flipped .landing__plan-flip__inner { transform: none; }
  .landing__plan-flip.is-flipped .landing__plan-flip__back { display: flex; }
  .landing__plan-flip__hint-icon { animation: none; }

  /* ── Smart Dashboard ── */
  .landing__smartdash-grid { grid-template-columns: 1fr; }
  .landing__smartdash-left { border-right: none; border-bottom: 1px solid rgba(255,255,255,0.06); }
  .landing__smartdash-metrics { grid-template-columns: repeat(2, 1fr); }
  .landing__smartdash-chart-bars { height: 90px; }
  .landing__smartdash-demo-banner { flex-direction: column; align-items: flex-start; gap: 0.6rem; }

  /* ── Mobile GPU performance ── */
  .landing__orb {
    filter: blur(20px) !important;
    animation: none !important;
    opacity: 0.08;
  }
  .landing__grid-pattern { display: none; }
  .landing__preview-line { animation: none; opacity: 0.6; }
  .preview-dot { animation: none; opacity: 0.5; }
  .preview-generating-text { animation: none; opacity: 0.5; }
  .landing__cursor { animation: none; opacity: 1; }
}
